using System;
using System.Collections.Generic;

class Program
{
    static bool IsPrime(int number)
    {
        if (number < 2) return false;

        for (int i = 2; i * i <= number; i++)
        {
            if (number % i == 0) return false;
        }
        return true;
    }

    static void Main()
    {
        Console.WriteLine("1-50 arasindaki asal sayilar:");
        List<int> primes = new List<int>();

        for (int i = 1; i <= 50; i++)
        {
            if (IsPrime(i))
            {
                primes.Add(i);
            }
        }

        Console.WriteLine(string.Join(", ", primes));
        Console.WriteLine("\nToplam asal sayi adedi: " + primes.Count);

        // Tekil kontrol
        int testNumber = 97;
        Console.WriteLine($"\n{testNumber} asal mi: {IsPrime(testNumber)}");

        testNumber = 100;
        Console.WriteLine($"{testNumber} asal mi: {IsPrime(testNumber)}");
    }
}
